#include<bits/stdc++.h>
using namespace std;

int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,ans=0;
        scanf("%d",&n);
        for(int i=1;i<=n/2;i++)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            int tmp=((x-1)|(y-1));
            int cnt=0;
            while(tmp&1)
            {
                cnt++;
                tmp>>=1;
            }
            ans^=cnt;
        }
        if(ans==0)
        {
            printf("NO\n");
        }
        else
        {
            printf("YES\n");
        }
    }
    return 0;
}
